+        // Upload file to OPFS and register
+        async function uploadFileToOPFS(file) {
+            const name = file.name.replace(/\.lance$/, '');
+            showStatus(`Uploading ${name}...`, 'info');
+
+            try {
+                // Read file content
+                const buffer = await file.arrayBuffer();
+
+                // Store in OPFS
+                const root = await navigator.storage.getDirectory();
+                const fileHandle = await root.getFileHandle(`${name}.lance`, { create: true });
+                const writable = await fileHandle.createWritable();
+                await writable.write(buffer);
+                await writable.close();
+
+                // Open as Lance file
+                const dataset = await lanceql.openMemory(new Uint8Array(buffer));
+
+                // Detect column types
+                let cols = dataset.numColumns;
+                try {
+                    const types = await dataset.detectColumnTypes();
+                    cols = types.length;
+                    dataset._columnTypes = types;
+                } catch (e) {}
+
+                // Register table
+                registerTable(name, {
+                    type: 'local',
+                    dataset,
+                    rows: dataset.rowCount || 0,
+                    cols
+                });
+
+                // Set as current file
+                $currentFile.set(dataset);
+                $columnTypes.set(dataset._columnTypes || []);
+                showColumnChips();
+
+                showStatus(`Uploaded "${name}" (${(buffer.byteLength / 1024 / 1024).toFixed(2)} MB)`, 'success');
+            } catch (err) {
+                showStatus(`Failed to upload: ${err.message}`, 'error');
+                console.error(err);
+            }
+        }
+
+        // Load OPFS tables on init
+        async function loadOPFSTables() {
+            try {
+                const root = await navigator.storage.getDirectory();
+                for await (const [name, handle] of root.entries()) {
+                    if (handle.kind === 'file' && name.endsWith('.lance')) {
+                        const file = await handle.getFile();
+                        const buffer = await file.arrayBuffer();
+                        const tableName = name.replace(/\.lance$/, '');
+
+                        const dataset = await lanceql.openMemory(new Uint8Array(buffer));
+                        let cols = dataset.numColumns;
+                        try {
+                            const types = await dataset.detectColumnTypes();
+                            cols = types.length;
+                            dataset._columnTypes = types;
+                        } catch (e) {}
+
+                        tablesRegistry.set(tableName, {
+                            type: 'local',
+                            dataset,
+                            rows: dataset.rowCount || 0,
+                            cols
+                        });
+                    }
+                }
+                renderTablesUI();
+            } catch (e) {
+                console.warn('Could not load OPFS tables:', e);
+            }
+        }
